// MARK: - Secure API Communication

class SecureAPIClient {
    static let shared = SecureAPIClient()
    
    private let baseURL: String
    private let session: URLSession
    private var authToken: String?
    private var refreshToken: String?
    private let tokenLock = NSLock()
    
    private init() {
        self.baseURL = "https://api.tradingplatform.com/v1"
        
        let config = URLSessionConfiguration.default
        config.tlsMinimumSupportedProtocolVersion = .TLSv12
        config.urlCache = nil
        config.requestCachePolicy = .reloadIgnoringLocalCacheData
        config.httpAdditionalHeaders = [
            "Content-Type": "application/json",
            "X-Platform": "iOS",
            "X-App-Version": Bundle.main.infoDictionary?["CFBundleShortVersionString"] as? String ?? "1.0"
        ]
        
        self.session = URLSession(configuration: config, delegate: SSLPinningDelegate(), delegateQueue: nil)
    }
    
    func setAuthToken(_ token: String, refresh: String) {
        tokenLock.lock()
        defer { tokenLock.unlock() }
        
        if let tokenData = token.data(using: .utf8) {
            KeychainManager.shared.save(tokenData, forKey: "auth_token")
        }
        if let refreshData = refresh.data(using: .utf8) {
            KeychainManager.shared.save(refreshData, forKey: "refresh_token")
        }
        
        self.authToken = token
        self.refreshToken = refresh
    }
    
    func loadStoredTokens() {
        tokenLock.lock()
        defer { tokenLock.unlock() }
        
        if let tokenData = KeychainManager.shared.load(forKey: "auth_token") {
            self.authToken = String(data: tokenData, encoding: .utf8)
        }
        if let refreshData = KeychainManager.shared.load(forKey: "refresh_token") {
            self.refreshToken = String(data: refreshData, encoding: .utf8)
        }
    }
    
    func clearTokens() {
        tokenLock.lock()
        defer { tokenLock.unlock() }
        KeychainManager.shared.delete(forKey: "auth_token")
        KeychainManager.shared.delete(forKey: "refresh_token")
        self.authToken = nil
        self.refreshToken = nil
    }
    
    private func createSignedRequest(endpoint: String, method: String, body: Data? = nil) -> URLRequest {
        var request = URLRequest(url: URL(string: "\(baseURL)\(endpoint)")!)
        request.httpMethod = method
        request.httpBody = body
        
        tokenLock.lock()
        if let token = authToken {
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        tokenLock.unlock()
        
        let timestamp = String(Int(Date().timeIntervalSince1970))
        request.setValue(timestamp, forHTTPHeaderField: "X-Timestamp")
        
        let nonce = UUID().uuidString
        request.setValue(nonce, forHTTPHeaderField: "X-Nonce")
        
        let signaturePayload = "\(method)\(endpoint)\(timestamp)\(nonce)\(body.map { String(data: $0, encoding: .utf8) ?? "" } ?? "")"
        let signature = generateHMAC(payload: signaturePayload)
        request.setValue(signature, forHTTPHeaderField: "X-Signature")
        
        return request
    }
    
    private func generateHMAC(payload: String) -> String {
        let key = SymmetricKey(data: "api_secret_key".data(using: .utf8)!)
        let signature = HMAC<SHA256>.authenticationCode(for: payload.data(using: .utf8)!, using: key)
        return Data(signature).base64EncodedString()
    }
    
    func request<T: Decodable>(endpoint: String, method: String = "GET", body: Encodable? = nil) async throws -> T {
        let encoder = JSONEncoder()
        encoder.dateEncodingStrategy = .iso8601
        let bodyData = try body.map { try encoder.encode($0) }
        
        let request = createSignedRequest(endpoint: endpoint, method: method, body: bodyData)
        
        let (data, response) = try await session.data(for: request)
        
        guard let httpResponse = response as? HTTPURLResponse else {
            throw APIError.invalidResponse
        }
        
        switch httpResponse.statusCode {
        case 200...299:
            let decoder = JSONDecoder()
            decoder.dateDecodingStrategy = .iso8601
            return try decoder.decode(T.self, from: data)
        case 401:
            try await refreshAuthToken()
            return try await self.request(endpoint: endpoint, method: method, body: body)
        case 429:
            throw APIError.rateLimited
        case 400...499:
            let errorResponse = try? JSONDecoder().decode(APIErrorResponse.self, from: data)
            throw APIError.clientError(httpResponse.statusCode, errorResponse?.message ?? "Client error")
        case 500...599:
            throw APIError.serverError(httpResponse.statusCode)
        default:
            throw APIError.unknown
        }
    }
    
    private func refreshAuthToken() async throws {
        tokenLock.lock()
        guard let refresh = refreshToken else {
            tokenLock.unlock()
            throw APIError.unauthorized
        }
        tokenLock.unlock()
        
        struct RefreshRequest: Encodable {
            let refreshToken: String
        }
        
        struct TokenResponse: Decodable {
            let accessToken: String
            let refreshToken: String
        }
        
        let body = try JSONEncoder().encode(RefreshRequest(refreshToken: refresh))
        let request = createSignedRequest(endpoint: "/auth/refresh", method: "POST", body: body)
        
        let (data, response) = try await session.data(for: request)
        
        guard let httpResponse = response as? HTTPURLResponse, httpResponse.statusCode == 200 else {
            clearTokens()
            throw APIError.unauthorized
        }
        
        let tokenResponse = try JSONDecoder().decode(TokenResponse.self, from: data)
        setAuthToken(tokenResponse.accessToken, refresh: tokenResponse.refreshToken)
    }
}

struct APIErrorResponse: Decodable {
    let message: String
    let code: String?
}

enum APIError: LocalizedError {
    case invalidResponse
    case unauthorized
    case rateLimited
    case clientError(Int, String)
    case serverError(Int)
    case unknown
    case networkUnavailable
    case decodingError
    
    var errorDescription: String? {
        switch self {
        case .invalidResponse: return "Invalid server response"
        case .unauthorized: return "Session expired. Please log in again."
        case .rateLimited: return "Too many requests. Please wait."
        case .clientError(_, let message): return message
        case .serverError(let code): return "Server error (\(code)). Please try again."
        case .unknown: return "An unknown error occurred"
        case .networkUnavailable: return "Network unavailable. Check your connection."
        case .decodingError: return "Failed to process server response"
        }
    }
}

// MARK: - SSL Pinning

class SSLPinningDelegate: NSObject, URLSessionDelegate {
    func urlSession(_ session: URLSession, didReceive challenge: URLAuthenticationChallenge, completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void) {
        guard let serverTrust = challenge.protectionSpace.serverTrust,
              let certificate = SecTrustGetCertificateAtIndex(serverTrust, 0) else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        let serverCertificateData = SecCertificateCopyData(certificate) as Data
        
        if let localCertPath = Bundle.main.path(forResource: "trading_api", ofType: "cer"),
           let localCertData = try? Data(contentsOf: URL(fileURLWithPath: localCertPath)) {
            if serverCertificateData == localCertData {
                completionHandler(.useCredential, URLCredential(trust: serverTrust))
                return
            }
        }
        
        // Fallback: standard validation for development
        var result = SecTrustResultType.invalid
        SecTrustEvaluate(serverTrust, &result)
        if result == .unspecified || result == .proceed {
            completionHandler(.useCredential, URLCredential(trust: serverTrust))
        } else {
            completionHandler(.cancelAuthenticationChallenge, nil)
        }
    }
}

// MARK: - Keychain Manager

class KeychainManager {
    static let shared = KeychainManager()
    private init() {}
    
    func save(_ data: Data, forKey key: String) {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly,
            kSecValueData as String: data
        ]
        
        SecItemDelete(query as CFDictionary)
        SecItemAdd(query as CFDictionary, nil)
    }
    
    func load(forKey key: String) -> Data? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        SecItemCopyMatching(query as CFDictionary, &result)
        return result as? Data
    }
    
    func delete(forKey key: String) {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key
        ]
        SecItemDelete(query as CFDictionary)
    }
}

// MARK: - Biometric Authentication

class BiometricAuthManager {
    static let shared = BiometricAuthManager()
    private let context = LAContext()
    
    var isBiometricAvailable: Bool {
        var error: NSError?
        return context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error)
    }
    
    var biometricType: LABiometryType {
        _ = context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: nil)
        return context.biometryType
    }
    
    func authenticate(reason: String) async throws -> Bool {
        let context = LAContext()
        context.localizedCancelTitle = "Cancel"
        
        return try await context.evaluatePolicy(
            .deviceOwnerAuthenticationWithBiometrics,
            localizedReason: reason
        )
    }
}

